// UNPATCHED SecEnumerateProcessContexts @ 0x14002CF04 — callback under shared lock, entry not pinned
void SecEnumerateProcessContexts(callback_t callback, void* context) {
    if (!(SecData->flags_4f8 & 4)) return;
    FltAcquirePushLockSharedEx(SecProcessTable + 8, 0);   // SHARED lock
    for (bucket = 0; bucket < 0x80; bucket++) {
        node = SecProcessTable->buckets[bucket];          // [SecProcessTable+0x140]
        while (node != sentinel) {
            entry = node - 0x10;
            node  = *node;                                 // advance before callback
            callback(entry, context);                      // callback WHILE lock held, entry not pinned
        }
    }
    FltReleasePushLockEx(SecProcessTable + 8, 0);
}

// PATCHED SecEnumerateProcessContexts @ 0x14002CFC0 — reference + snapshot, release, then callback
void SecEnumerateProcessContexts(callback_t callback, void* context) {
    if (!(SecData->flags_4f8 & 4)) return;
    FltAcquirePushLockSharedEx(SecProcessTable + 8, 0);
    if (SecData[0x510] & 1) { /* old in-lock path, only when bit SET */ ... return; }
    int count = SecProcessTable->entry_count;             // [SecProcessTable+0x148]
    void** snap = ExAllocatePoolWithTag(PagedPool, count*8, 'Scce');
    for (each entry) { SecReferenceProcessContext(entry); snap[n++] = entry; }
    FltReleasePushLockEx(SecProcessTable + 8, 0);          // release BEFORE callbacks
    for (i = 0; i < n; i++) { callback(snap[i], context); SecReleaseProcessContext(snap[i]); }
    SecFreePool(snap, 'Scce');
}

// UNPATCHED SecPerformProcessAssertionsForAllProcesses @ 0x14002DD1C
int64_t SecPerformProcessAssertionsForAllProcesses() {
    FltAcquirePushLockSharedEx(SecProcessTable + 8, 0);   // SHARED lock
    for (bucket = 0; bucket < 0x80; bucket++) {
        node = SecProcessTable->buckets[bucket];
        while (node != sentinel) {
            entry = node - 0x10;
            node  = *node;                                 // advance
            if (PsLookupProcessByProcessId(entry->ProcessId /*[+0x20]*/, &proc) >= 0) {
                SecDetPerformProcessAssertionsWithContext(proc, entry, 0); // entry not pinned
                ObfDereferenceObject(proc);
            }
        }
    }
    return FltReleasePushLockEx(SecProcessTable + 8, 0);
}

